// ✅ Recommended — structured request logging
const morgan = require('morgan');
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [new winston.transports.Console()],
});

// Log all requests
app.use(morgan('combined', {
  stream: { write: (message) => logger.info(message.trim()) },
}));

// Centralized error handler
app.use((err, req, res, next) => {
  logger.error({ message: err.message, stack: err.stack, url: req.url });
  res.status(500).json({ error: 'Internal Server Error' }); // Never leak stack traces
});
```

---

#### 7. `/health` Endpoint Information Disclosure
**OWASP A05 (Security Misconfiguration)**

The `/health` route currently returns only `{ status: 'ok', timestamp: ... }`, which is fine. However, health endpoints are often extended over time to include version info, dependency status, uptime, environment names, etc. — all of which can aid reconnaissance.

**Recommendation:** Keep health endpoints minimal and, if richer data is needed internally, gate it behind authentication or restrict it to internal network access.

```js
// ✅ Minimal health check — no sensitive metadata
